// # supacode-managed-hook
//
// Generated by Supacode — do not edit. Bridges OpenCode plugin events to
// Supacode's OSC 3008 agent-presence protocol by running the same guarded
// shell command Supacode installs for every other agent. The command checks
// SUPACODE_SURFACE_ID first, so it is inert outside a Supacode surface and
// safe to keep installed anywhere.
//
// Presence only: OpenCode's session.idle event carries no assistant text
// (unlike Claude Code's Stop hook stdin), so the system-notification leg is
// intentionally omitted rather than fed a fabricated body.
export const SupacodePresence = async ({ $ }) => {
  const emit = (command) => $`sh -c ${command}`.quiet().nothrow()

  // Agent is now present in this surface.
  await emit("[ -n \"${SUPACODE_SURFACE_ID:-}\" ] && { __tty=$(ps -o tty= -p \"$PPID\" 2>\/dev\/null | tr -d '[:space:]'); case \"$__tty\" in *[0-9]*) __tty=\"\/dev\/${__tty#\/dev\/}\";; *) __tty=\"\/dev\/tty\";; esac; __sp=\"\"; [ -n \"${SUPACODE_SOCKET_PATH:-}\" ] && __sp=\";pid=$PPID\"; printf '\\033]3008;start=opencode;event=session_start%s\\033\\\\' \"$__sp\" > \"$__tty\"; } >\/dev\/null 2>&1 || true # supacode-managed-hook")

  return {
    // Agent (and its surface presence) is going away.
    dispose: async () => {
      await emit("[ -n \"${SUPACODE_SURFACE_ID:-}\" ] && { __tty=$(ps -o tty= -p \"$PPID\" 2>\/dev\/null | tr -d '[:space:]'); case \"$__tty\" in *[0-9]*) __tty=\"\/dev\/${__tty#\/dev\/}\";; *) __tty=\"\/dev\/tty\";; esac; __sp=\"\"; [ -n \"${SUPACODE_SOCKET_PATH:-}\" ] && __sp=\";pid=$PPID\"; printf '\\033]3008;end=opencode;event=session_end%s\\033\\\\' \"$__sp\" > \"$__tty\"; __sp=\"\"; [ -n \"${SUPACODE_SOCKET_PATH:-}\" ] && __sp=\";pid=$PPID\"; printf '\\033]3008;start=opencode;event=idle%s\\033\\\\' \"$__sp\" > \"$__tty\"; } >\/dev\/null 2>&1 || true # supacode-managed-hook")
    },
    // Tool-level activity shimmer: a tool started / finished.
    "tool.execute.before": async () => {
      await emit("[ -n \"${SUPACODE_SURFACE_ID:-}\" ] && { __tty=$(ps -o tty= -p \"$PPID\" 2>\/dev\/null | tr -d '[:space:]'); case \"$__tty\" in *[0-9]*) __tty=\"\/dev\/${__tty#\/dev\/}\";; *) __tty=\"\/dev\/tty\";; esac; __sp=\"\"; [ -n \"${SUPACODE_SOCKET_PATH:-}\" ] && __sp=\";pid=$PPID\"; printf '\\033]3008;start=opencode;event=busy%s\\033\\\\' \"$__sp\" > \"$__tty\"; } >\/dev\/null 2>&1 || true # supacode-managed-hook")
    },
    "tool.execute.after": async () => {
      await emit("[ -n \"${SUPACODE_SURFACE_ID:-}\" ] && { __tty=$(ps -o tty= -p \"$PPID\" 2>\/dev\/null | tr -d '[:space:]'); case \"$__tty\" in *[0-9]*) __tty=\"\/dev\/${__tty#\/dev\/}\";; *) __tty=\"\/dev\/tty\";; esac; __sp=\"\"; [ -n \"${SUPACODE_SOCKET_PATH:-}\" ] && __sp=\";pid=$PPID\"; printf '\\033]3008;start=opencode;event=idle%s\\033\\\\' \"$__sp\" > \"$__tty\"; } >\/dev\/null 2>&1 || true # supacode-managed-hook")
    },
    // A permission prompt is the "needs you" state.
    "permission.ask": async () => {
      await emit("[ -n \"${SUPACODE_SURFACE_ID:-}\" ] && { __tty=$(ps -o tty= -p \"$PPID\" 2>\/dev\/null | tr -d '[:space:]'); case \"$__tty\" in *[0-9]*) __tty=\"\/dev\/${__tty#\/dev\/}\";; *) __tty=\"\/dev\/tty\";; esac; __sp=\"\"; [ -n \"${SUPACODE_SOCKET_PATH:-}\" ] && __sp=\";pid=$PPID\"; printf '\\033]3008;start=opencode;event=awaiting_input%s\\033\\\\' \"$__sp\" > \"$__tty\"; } >\/dev\/null 2>&1 || true # supacode-managed-hook")
    },
    event: async ({ event }) => {
      if (event.type === "session.idle") {
        await emit("[ -n \"${SUPACODE_SURFACE_ID:-}\" ] && { __tty=$(ps -o tty= -p \"$PPID\" 2>\/dev\/null | tr -d '[:space:]'); case \"$__tty\" in *[0-9]*) __tty=\"\/dev\/${__tty#\/dev\/}\";; *) __tty=\"\/dev\/tty\";; esac; __sp=\"\"; [ -n \"${SUPACODE_SOCKET_PATH:-}\" ] && __sp=\";pid=$PPID\"; printf '\\033]3008;start=opencode;event=idle%s\\033\\\\' \"$__sp\" > \"$__tty\"; } >\/dev\/null 2>&1 || true # supacode-managed-hook")
      } else if (event.type === "permission.replied") {
        await emit("[ -n \"${SUPACODE_SURFACE_ID:-}\" ] && { __tty=$(ps -o tty= -p \"$PPID\" 2>\/dev\/null | tr -d '[:space:]'); case \"$__tty\" in *[0-9]*) __tty=\"\/dev\/${__tty#\/dev\/}\";; *) __tty=\"\/dev\/tty\";; esac; __sp=\"\"; [ -n \"${SUPACODE_SOCKET_PATH:-}\" ] && __sp=\";pid=$PPID\"; printf '\\033]3008;start=opencode;event=busy%s\\033\\\\' \"$__sp\" > \"$__tty\"; } >\/dev\/null 2>&1 || true # supacode-managed-hook")
      }
    },
  }
}